const express = require('express');
const jwt = require('jsonwebtoken');
const crypto = require('crypto');

// ─── Configuration ───────────────────────────────────────────────────────────

// Generate a strong secret key (in production, load from env / secrets manager)
// Minimum 256 bits for HS256; we use 512 bits for extra margin.
const JWT_SECRET = process.env.JWT_SECRET;

if (!JWT_SECRET || Buffer.byteLength(JWT_SECRET, 'utf8') < 32) {
  throw new Error(
    'JWT_SECRET must be set and at least 32 bytes (256 bits). ' +
    'Generate one with: node -e "console.log(require(\'crypto\').randomBytes(64).toString(\'hex\'))"'
  );
}

// Explicit algorithm allowlist — prevents "alg: none" and RS/HS confusion attacks
const ALLOWED_ALGORITHMS = ['HS256'];

// Token lifetime defaults
const ACCESS_TOKEN_TTL = '15m';
const ISSUER = 'myapp-auth-service';
const AUDIENCE = 'myapp-api';

// ─── Token Generation ────────────────────────────────────────────────────────

/**
 * Issues a short-lived access token with a unique jti for replay resistance.
 *
 * @param {Object} user - Must contain at least { id, email, roles }
 * @returns {string} Signed JWT
 */
function generateAccessToken(user) {
  if (!user || !user.id) {
    throw new Error('user.id is required to generate a token');
  }

  const jti = crypto.randomUUID();          // unique token ID (replay resistance)
  const iat = Math.floor(Date.now() / 1000); // explicit issued-at

  const payload = {
    sub: String(user.id),                    // subject — always a string
    email: user.email || null,
    roles: Array.isArray(user.roles) ? user.roles : [],
    jti,
    iat,
  };

  return jwt.sign(payload, JWT_SECRET, {
    algorithm: ALLOWED_ALGORITHMS[0],
    expiresIn: ACCESS_TOKEN_TTL,
    issuer: ISSUER,
    audience: AUDIENCE,
    // noTimestamp is NOT set — we want iat for freshness checks
  });
}

// ─── Authentication Middleware ────────────────────────────────────────────────

/**
 * Express middleware that:
 *  1. Extracts the Bearer token from the Authorization header.
 *  2. Verifies signature with an explicit algorithm allowlist.
 *  3. Validates exp, nbf, iss, aud claims.
 *  4. Attaches decoded user info to req.user.
 *
 * Designed for high throughput — verification is purely cryptographic (no DB
 * or blocklist lookup on the hot path). Short TTLs + jti make revocation
 * practical via a thin in-memory cache when needed (see optional layer below).
 */
function authenticateToken(req, res, next) {
  // 1. Extract token ─────────────────────────────────────────────────────────
  const authHeader = req.headers['authorization'];

  if (!authHeader) {
    return res.status(401).json({ error: 'Authorization header is required' });
  }

  // Strict "Bearer <token>" format
  const parts = authHeader.split(' ');
  if (parts.length !== 2 || parts[0] !== 'Bearer') {
    return res.status(401).json({ error: 'Authorization header must use Bearer scheme' });
  }

  const token = parts[1];

  if (!token || token.length === 0) {
    return res.status(401).json({ error: 'Token is missing' });
  }

  // 2. Verify ────────────────────────────────────────────────────────────────
  try {
    const decoded = jwt.verify(token, JWT_SECRET, {
      algorithms: ALLOWED_ALGORITHMS,   // CRITICAL: prevents alg-none & confusion
      issuer: ISSUER,                   // reject tokens from other issuers
      audience: AUDIENCE,               // reject tokens for other audiences
      clockTolerance: 5,                // 5 s skew tolerance
      maxAge: ACCESS_TOKEN_TTL,         // reject tokens older than TTL even if exp faked
      complete: false,                  // return payload only
    });

    // 3. Sanity-check required claims ────────────────────────────────────────
    if (!decoded.sub) {
      return res.status(401).json({ error: 'Token missing subject claim' });
    }
    if (!decoded.jti) {
      return res.status(401).json({ error: 'Token missing jti claim' });
    }
    if (typeof decoded.exp !== 'number') {
      return res.status(401).json({ error: 'Token missing expiration claim' });
    }

    // 4. Attach user context ─────────────────────────────────────────────────
    req.user = Object.freeze({
      id: decoded.sub,
      email: decoded.email || null,
      roles: Array.isArray(decoded.roles) ? decoded.roles : [],
      jti: decoded.jti,
      iat: decoded.iat,
      exp: decoded.exp,
    });

    return next();
  } catch (err) {
    // Map jsonwebtoken error types to appropriate responses
    if (err.name === 'TokenExpiredError') {
      return res.status(401).json({ error: 'Token has expired' });
    }
    if (err.name === 'JsonWebTokenError') {
      // Covers: invalid signature, invalid algorithm, malformed token
      return res.status(401).json({ error: 'Invalid token' });
    }
    if (err.name === 'NotBeforeError') {
      return res.status(401).json({ error: 'Token is not yet active' });
    }
    // Unexpected error — don't leak internals
    console.error('JWT verification error:', err);
    return res.status(401).json({ error: 'Authentication failed' });
  }
}

// ─── Role-Based Authorization Middleware ──────────────────────────────────────

/**
 * Factory that returns middleware requiring the authenticated user to have
 * at least one of the specified roles.
 *
 * @param  {...string} requiredRoles
 */
function authorizeRoles(...requiredRoles) {
  if (requiredRoles.length === 0) {
    throw new Error('authorizeRoles requires at least one role');
  }

  return (req, res, next) => {
    if (!req.user) {
      return res.status(401).json({ error: 'Authentication required' });
    }

    const hasRole = req.user.roles.some((role) => requiredRoles.includes(role));
    if (!hasRole) {
      return res.status(403).json({ error: 'Insufficient permissions' });
    }

    return next();
  };
}

// ─── Optional: Lightweight In-Memory JTI Blocklist ───────────────────────────
//
// For the rare case where you need to revoke a token before it expires (e.g.
// user logout, password change). Because tokens are short-lived (15 min), the
// blocklist stays tiny and entries auto-expire.
//
// This is O(1) per request and adds negligible latency.

class JtiBlocklist {
  constructor() {
    this.blocked = new Map(); // jti → expiry timestamp (seconds)
  }

  /**
   * Add a jti to the blocklist. It will be automatically pruned after the
   * token's original expiry time.
   */
  revoke(jti, expTimestamp) {
    this.blocked.set(jti, expTimestamp);
  }

  isRevoked(jti) {
    return this.blocked.has(jti);
  }

  /** Prune expired entries to keep memory bounded. Call periodically. */
  prune() {
    const now = Math.floor(Date.now() / 1000);
    for (const [jti, exp] of this.blocked) {
      if (exp <= now) {
        this.blocked.delete(jti);
      }
    }
  }
}

const blocklist = new JtiBlocklist();

// Prune every 60 seconds
setInterval(() => blocklist.prune(), 60_000).unref();

/**
 * Optional middleware that checks the in-memory blocklist.
 * Place AFTER authenticateToken if you need revocation support.
 */
function checkBlocklist(req, res, next) {
  if (req.user && blocklist.isRevoked(req.user.jti)) {
    return res.status(401).json({ error: 'Token has been revoked' });
  }
  return next();
}

